[CmdletBinding()]
param([Parameter(Mandatory)][string]$ProjectRoot,[Parameter(Mandatory)][ValidateSet('product-studio','repo-explorer','frontend-builder','backend-builder','database-architect','integration-builder','test-engineer','code-reviewer','security-auditor','refactor-engineer','performance-auditor','browser-qa','release-engineer','operations-engineer')][string]$Role,[Parameter(Mandatory)][string]$State,[ValidateSet('lean','standard','thorough')][string]$Mode='standard',[Parameter(Mandatory)][string]$Task,[string[]]$AffectedPath=@(),[switch]$Diagnostic)
$ErrorActionPreference='Stop';. (Join-Path $PSScriptRoot '../records/Test-RequiredProjectRecords.ps1');. (Join-Path $PSScriptRoot '../security/Test-ProjectRelativePath.ps1')
$project=(Resolve-Path -LiteralPath $ProjectRoot).Path;$studio=Join-Path $project '.studio';$root=(Resolve-Path (Join-Path $PSScriptRoot '../..')).Path;$validation=Test-RequiredProjectRecords $project;$req=$validation.requirements;if(Test-Path $studio){& (Join-Path $PSScriptRoot 'build_repo_map.ps1') -ProjectRoot $project|Out-Null};$missing=@($validation.checks|Where-Object{$_.status -eq 'missing'}|ForEach-Object{$_.record.path});$invalid=@($validation.checks|Where-Object{-not $_.valid -and $_.status -ne 'missing'}|ForEach-Object{$_.record.path});$blocking=@();if(-not $validation.valid){$blocking+='Required project records are missing or invalid.'};if($State -in @('implementation-planning','implementation','specialist-verification') -and (-not $req.productType -or $req.productType -eq 'unknown')){$blocking+='Product type is unresolved.'};if($State -in @('implementation-planning','implementation','specialist-verification') -and @($req.surfaces).Count -eq 0){$blocking+='Active surfaces are unresolved.'}
$badPaths=@($AffectedPath|Where-Object{-not(Test-ProjectRelativePath $project $_ -AllowGlob).valid});if($badPaths.Count){throw "AFFECTED_PATH_INVALID: $($badPaths -join ', ')"};$map=if(Test-Path (Join-Path $studio 'REPO_MAP.json')){Get-Content -Raw (Join-Path $studio 'REPO_MAP.json')|ConvertFrom-Json}else{$null};$stack=@($map.frameworks)+@($map.languages);$index=Get-Content -Raw (Join-Path $root 'knowledge/context/RULE_ROUTE_INDEX.json')|ConvertFrom-Json;$rules=@($index.rules|Where-Object{($_.roles -contains '*' -or $_.roles -contains $Role) -and ($_.stages -contains '*' -or $_.stages -contains $State) -and ($_.productTypes.Count -eq 0 -or $_.productTypes -contains $req.productType) -and ($_.surfaces.Count -eq 0 -or @($_.surfaces|Where-Object{$req.surfaces -contains $_}).Count) -and ($_.stacks.Count -eq 0 -or @($_.stacks|Where-Object{$stack -contains $_}).Count)}|Sort-Object @{e='priority';Descending=$true},id);$selected=@($rules|ForEach-Object{[ordered]@{id=$_.id;summary=$_.summary;source=$_.source;strength=$_.strength;selectedBecause=[ordered]@{role=$Role;stage=$State;productType=$req.productType;surface=@($_.surfaces|Where-Object{$req.surfaces -contains $_}|Select-Object -First 1)}}});$manifest=[ordered]@{schemaVersion=1;status=if($blocking.Count){'blocked'}else{'ready'};generatedAt=[DateTime]::UtcNow.ToString('o');projectRoot=$project;projectState=$req.state.record.metadata.data.currentState;workflowMode=$req.workflowMode;role=$Role;task=$Task;productType=$req.productType;surfaces=@($req.surfaces);activeScope=@($req.state.record.metadata.data.activeScope);stack=@($stack|Sort-Object -Unique);requiredRecords=@($req.required|ForEach-Object name);missingRequiredRecords=$missing;invalidRequiredRecords=$invalid;optionalRecords=@();unresolved=@();blockingReasons=$blocking;selectedRules=$selected;selectedRuleIds=@($selected|ForEach-Object id);repositoryPaths=@($AffectedPath);recordReasons=@{}}
$runtime=[IO.Path]::GetFullPath((Join-Path $studio 'runtime/context'));New-Item -ItemType Directory -Force -Path $runtime|Out-Null;$output=[IO.Path]::GetFullPath((Join-Path $runtime ($Role+'.json')));if(-not $output.StartsWith($runtime+[IO.Path]::DirectorySeparatorChar,[StringComparison]::OrdinalIgnoreCase)){throw 'CONTEXT_OUTPUT_ESCAPE'};$manifest|ConvertTo-Json -Depth 12|Set-Content -LiteralPath $output -Encoding utf8;if($manifest.status -eq 'blocked' -and -not $Diagnostic){throw "Context compilation blocked. Manifest: $output"};Write-Host "Context manifest generated: $output ($($manifest.status))"
